import numpy as npclass ResourceAllocationDP():    def __init__(self, stages_num:int, total_resources:int, mode:str, operator:str='sum'):        self.stages_num = stages_num        self.total_resources = total_resources                if not (mode == 'Maximize' or mode == 'Minimize'):            raise ValueError('mode can only be either Maximize or Minimize')        self.mode = mode        self.mode_operator = np.max if mode == 'Maximize' else np.min        self.mode_idx_op = np.argmax if mode == 'Maximize' else np.argmin                if not (operator == 'sum' or operator == 'multiply'):            raise ValueError('operator can only be either sum or multiply')        self.operator = np.add if operator == 'sum' else np.multiply        fill_val = -np.inf if mode == 'Maximize' else np.inf        self.DP_table = np.full((total_resources + 1, self.stages_num + 1), fill_val)        self.DP_table[0, 0] = 1.0 if operator == 'multiply' else 0.0                self.policy_table = np.zeros((total_resources + 1, self.stages_num + 1))                def solve(self, reward_matrix:np.ndarray):        """solve the DP problem through forward method           reward_matrix: shape (total_resources, stages_num)"""        for stage in range(1, self.stages_num + 1):            for res_idx in range(self.total_resources + 1):                fitness_lst = []                for cur_res_idx in range(res_idx + 1):                    f = self.operator(self.DP_table[res_idx - cur_res_idx, stage - 1],                                       reward_matrix[cur_res_idx, stage - 1])                    fitness_lst.append(f)                                self.DP_table[res_idx, stage] = self.mode_operator(fitness_lst)                self.policy_table[res_idx, stage] = self.mode_idx_op(fitness_lst)        best_fitness = self.mode_operator(self.DP_table[:, -1])        used_resource = self.mode_idx_op(self.DP_table[:, -1])                return best_fitness, self._traceback(used_resource)        def _traceback(self, used_resource:int):        """traceback the path by the policy table"""        path = np.zeros(self.stages_num)        n_stage = self.stages_num        while n_stage > 0:            path[n_stage - 1] = self.policy_table[used_resource, n_stage]            used_resource -= int(self.policy_table[used_resource, n_stage])            n_stage -= 1                return pathdef test_scientist_allocation():    print("--- Testing Problem 1: Scientist Allocation ---")    # 原数据：行是 Team，列是科学家数    P = np.array([        [0.4, 0.2, 0.15],        [0.6, 0.4, 0.2],        [0.8, 0.5, 0.3]    ])        # 实例化类    solver = ResourceAllocationDP(stages_num=3, total_resources=2, mode='Minimize', operator='multiply')        # 传入时使用 P.T，使其变成 (资源数3, 阶段数3)    best_prob, allocation = solver.solve(P.T)        print(f"Minimum Failure Probability: {best_prob:.3f}")    print(f"Optimal Allocation (Team 1, Team 2, Team 3): {allocation}\n")# ==========================================# 3. 测试题目 2：选票分配 (最大化求和)# ==========================================def test_election_allocation():    print("--- Testing Problem 2: Election Allocation ---")    # 原数据：行是 Division，列是志愿者数    V = np.array([        [0, 22, 39, 52, 60, 66, 71],        [0, 17, 35, 51, 62, 70, 77],        [0, 30, 40, 44, 47, 49, 50],        [0, 10, 21, 29, 36, 42, 47]    ])        # 实例化类    solver = ResourceAllocationDP(stages_num=4, total_resources=6, mode='Maximize', operator='sum')        # 传入时使用 V.T，使其变成 (资源数7, 阶段数4)    max_votes, allocation = solver.solve(V.T)        print(f"Maximum Additional Votes: {max_votes}")    print(f"Optimal Allocation (Div 1, Div 2, Div 3, Div 4): {allocation}\n")# 运行测试if __name__ == '__main__':    test_scientist_allocation()    test_election_allocation()